#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        while (Q--) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int L, R;
                scanf("%d %d", &L, &R);
                int* freq = (int*)malloc(R * sizeof(int));
                for (int i = 0; i < R; i++) {
                    freq[i] = 0;
                }
                for (int i = L - 1; i < R; i++) {
                    for (int j = 0; j < arr[i]; j++) {
                        freq[j]++;
                    }
                }
                int mode = 0, maxFreq = 0;
                for (int i = 0; i < R; i++) {
                    if (freq[i] > maxFreq) {
                        maxFreq = freq[i];
                        mode = i;
                    }
                }
                int median = 0;
                int count = 0;
                for (int i = 0; i < R; i++) {
                    count += freq[i];
                    if (count >= (R + 1) / 2) {
                        median = i;
                        break;
                    }
                }
                printf("%d\n", lcm(mode, median));
                free(freq);
            } else {
                int i, x;
                scanf("%d %d", &i, &x);
                arr[i - 1] = x;
            }
        }
        free(arr);
    }
    return 0;
}

