        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int type = sc.nextInt();
                if (type == 1) {
                    int L = sc.nextInt();
                    int R = sc.nextInt();
                    int[] freq = new int[R];
                    for (int i = L - 1; i < R; i++) {
                        for (int j = 0; j < arr[i]; j++) {
                            freq[j]++;
                        }
                    }
                    int mode = 0, maxFreq = 0;
                    for (int i = 0; i < R; i++) {
                        if (freq[i] > maxFreq) {
                            maxFreq = freq[i];
                            mode = i;
                        }
                    }
                    int median = 0;
                    int count = 0;
                    for (int i = 0; i < R; i++) {
                        count += freq[i];
                        if (count >= (R + 1) / 2) {
                            median = i;
                            break;
                        }
                    }
                    System.out.println(lcm(mode, median));
                } else {
                    int i = sc.nextInt();
                    int x = sc.nextInt();
                    arr[i - 1] = x;
                }
            }
        }
    }

    public static int gcd(int a, int b) {
        if (b == 0)
            return a;
        return gcd(b, a % b);
    }

    public static int lcm(int a, int b) {
        return (a * b) / gcd(a, b);
    }
}

